import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote — base premiums (single item)", () => {
    it.todo("should quote 105 G for a single plain sword (100 base + 5 fee)");
    it.todo("should quote 65 G for a single plain amulet (60 base + 5 fee)");
    it.todo("should quote 85 G for a single plain staff (80 base + 5 fee)");
    it.todo("should quote 45 G for a single plain potion (40 base + 5 fee)");
    it.todo("should quote 30 G for a single rune (25 base + 5 fee)");
    it.todo("should quote 30 G for a single moonstone (25 base + 5 fee)");
  });

  describe("Quote — empty policy", () => {
    it.todo("should quote 5 G for an empty item list (only processing fee)");
  });

  describe("Quote — component building blocks", () => {
    it.todo("should charge 50 G base for 2 runes (no block)");
    it.todo("should charge 60 G base for 3 runes (block of 3 alike applies)");
    it.todo("should charge 100 G base for 4 runes (no block — block requires exactly 3)");
    it.todo("should charge 175 G base for 7 runes (one block of 3 + 4 leftover)");
    it.todo("should charge 75 G base for 2 runes + 1 moonstone (no block: different types)");
    it.todo("should charge 120 G base for 3 runes + 3 moonstones (two separate blocks)");
  });

  describe("Quote — item-specific modifiers", () => {
    it.todo("should add 50% curse surcharge to a cursed sword's base premium");
    it.todo("should add 30% high-enchantment surcharge to a sword with enchantment exactly 5");
    it.todo("should not add high-enchantment surcharge to a sword with enchantment 4");
    it.todo("should apply both curse and high-enchantment surcharges to a cursed sword with enchantment 5");
  });

  describe("Quote — policy-wide modifiers", () => {
    it.todo("should apply 20% loyalty discount for a customer with exactly 2 years with MHPCO");
    it.todo("should not apply loyalty discount for a customer with fewer than 2 years");
    it.todo("should add 10% first-insurance surcharge on the policy base premium");
    it.todo("should apply 15% follow-up discount on each quote after the customer's first in a scenario");
  });

  describe("Quote — modifier scope on multi-item policies", () => {
    it.todo("should apply the curse surcharge only to the cursed item's base premium, not the policy total");
  });

  describe("Quote — rounding", () => {
    it.todo("should round the final premium up to the next whole G");
  });

  describe("Quote — integration examples", () => {
    it.todo("should quote 165 G for a newcomer's cursed steel sword (enchantment 3, 0 years)");
    it.todo("should quote 160 G for a long-standing customer's second quote (cursed steel sword enchantment 7, 3 years)");
  });

  describe("Claim — standard reimbursement", () => {
    it.todo("should pay 400 G for a steel sword (enchantment 3) damaged 500 G (full minus 100 deductible)");
    it.todo("should pay 100 G for a rune damaged 200 G (full minus 100 deductible, no special clause)");
  });

  describe("Claim — special clauses", () => {
    it.todo("should reimburse 50% then deduct for a steel sword enchantment 9 damaged 1000 G → 400 G");
    it.todo("should fully reimburse then deduct for a dragon-material sword enchantment 5 damaged 800 G → 700 G");
    it.todo("should apply the 50% rule then deduct for a dragon sword enchantment 8 damaged 1000 G → 400 G");
    it.todo("should let the 50% rule win over dragon material for a dragon sword enchantment 9 damaged 1000 G → 400 G");
  });

  describe("Claim — deductible per damage event", () => {
    it.todo("should apply the 100 G deductible once per damaged item (sword 500 + amulet 300 → 600 G)");
  });

  describe("Claim — rounding", () => {
    it.todo("should round the final payout down to the previous whole G");
  });

  describe("Claim — cap based on unmodified insurance sum", () => {
    it.todo("should cap a sword+amulet policy at 3200 G (sum 1600)");
    it.todo("should cap a sword+3-runes policy at 3500 G (sum 1750, block discount does not lower the sum)");
    it.todo("should cap a two-sword policy at 4000 G (sum 2000)");
  });

  describe("Claim — cap exhaustion across successive claims", () => {
    it.todo("should report remainingCap after a single claim (sword cap 2000, claim 1500 → payout 1400, remaining 600)");
    it.todo("should limit a later claim to the remaining cap (second claim 1500 → payout 600, remaining 0)");
  });

  describe("Claim — multiple items of the same type", () => {
    it.todo("should treat each same-type damage entry as a separate damage with its own deductible");
  });

  describe("CLI scenario output shape", () => {
    it.todo("should return a results array of the same length and order as the input steps");
    it.todo("should return { premium } for a quote step and { payout, remainingCap } for a claim step");
  });

  describe("Error handling", () => {
    it.todo("should reject a quote containing an unknown item type (e.g. broomstick)");
    it.todo("should reject a claim whose damage item is not part of the policy");
    it.todo("should reject a claim with more same-type damage entries than the policy covers");
    it.todo("should reject a claim with a negative damage amount");
  });
});
